## Key Concepts

### Pages vs Features

- **Pages** (`/pages`): Astro pages that define routes
- **Features** (`/features`): Business logic and feature-specific components

Example:
```
pages/tasks.astro
  ↓ (imports)
features/tasks/TasksPage.tsx
  ↓ (contains)
components/widgets/TaskCard.tsx
  ↓ (uses)
store/taskStore.ts
```

### State Management (Zustand)

Stores manage global application state:

```typescript
// authStore.ts
import { create } from 'zustand';

interface AuthState {
  user: User | null;
  token: string | null;
  isLoading: boolean;
  login: (email: string, password: string) => Promise<void>;
  logout: () => void;
  setUser: (user: User) => void;
}

const useAuthStore = create<AuthState>((set) => ({
  user: null,
  token: null,
  isLoading: false,
  
  login: async (email, password) => {
    set({ isLoading: true });
    try {
      const response = await authService.login(email, password);
      set({ 
        user: response.user, 
        token: response.token,
        isLoading: false
      });
      localStorage.setItem('token', response.token);
    } catch (error) {
      set({ isLoading: false });
      throw error;
    }
  },
  
  logout: () => {
    set({ user: null, token: null });
    localStorage.removeItem('token');
  },
  
  setUser: (user) => set({ user })
}));

export default useAuthStore;
```

### API Communication

```typescript
// services/api.ts
import axios from 'axios';
import { useAuthStore } from '../store/authStore';

const API_URL = import.meta.env.PUBLIC_API_URL || 'http://localhost:3000/api';

const api = axios.create({
  baseURL: API_URL
});

// Add token to requests
api.interceptors.request.use(
  (config) => {
    const token = useAuthStore.getState().token;
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => Promise.reject(error)
);

// Handle response errors
api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response?.status === 401) {
      // Token expired, redirect to login
      window.location.href = '/login';
    }
    return Promise.reject(error);
  }
);

export default api;
```

### Custom Hooks

Hooks encapsulate reusable logic:

```typescript
// hooks/useTasks.ts
import { useState, useEffect } from 'react';
import { useTaskStore } from '../store/taskStore';
import { taskService } from '../services/taskService';

export const useTasks = () => {
  const tasks = useTaskStore((state) => state.tasks);
  const setTasks = useTaskStore((state) => state.setTasks);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  
  const fetchTasks = async () => {
    setIsLoading(true);
    try {
      const data = await taskService.listTasks();
      setTasks(data);
      setError(null);
    } catch (err) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };
  
  useEffect(() => {
    fetchTasks();
  }, []);
  
  return { tasks, isLoading, error, refetch: fetchTasks };
};
```

### Real-time Socket Integration

```typescript
// hooks/useSocket.ts
import { useEffect } from 'react';
import { io } from 'socket.io-client';
import { useAuthStore } from '../store/authStore';
import { useRealtimeStore } from '../store/realtimeStore';

export const useSocket = () => {
  const token = useAuthStore((state) => state.token);
  const updateTask = useRealtimeStore((state) => state.updateTask);
  const addNotification = useRealtimeStore((state) => state.addNotification);
  
  useEffect(() => {
    if (!token) return;
    
    const socket = io(import.meta.env.PUBLIC_API_URL, {
      auth: { token }
    });
    
    socket.on('task-updated', (data) => {
      updateTask(data);
    });
    
    socket.on('notification-received', (notification) => {
      addNotification(notification);
    });
    
    return () => {
      socket.disconnect();
    };
  }, [token]);
};
```

## Component Examples

### Protected Route Component

```typescript
// components/auth/AuthGuard.tsx
import { ReactNode } from 'react';
import { useAuthStore } from '../../store/authStore';

interface AuthGuardProps {
  requiredRole?: 'Admin' | 'Superadmin' | 'Standard_User';
  children: ReactNode;
}

export const AuthGuard = ({ requiredRole, children }: AuthGuardProps) => {
  const user = useAuthStore((state) => state.user);
  
  if (!user) {
    window.location.href = '/login';
    return null;
  }
  
  if (requiredRole && user.global_role !== requiredRole) {
    return <div>You don't have permission to view this content</div>;
  }
  
  return <>{children}</>;
};
